mamba install -y r-base r-ggplot2 && Rscript -e 'library(DESeq2); loGlu <- read.csv("./examples/case1.1/output/LoGlu_Rep1_2.counts"); hiGlu <- read.csv("./examples/case1.1/output/HiGlu_Rep1_2.counts"); dds <- DESeqDataSetFromMatrix(countData = c(loGlu, hiGlu), colData = DataFrame(condition = c(rep("LoGlu", 2), rep("HiGlu", 2))), design = ~ condition); dds <- DESeq(dds); resultsNames(dds); res <- results(dds); resOrdered <- res[order(res$pvalue), ]; write.csv(resOrdered, "./examples/case1.1/output/DESeq2_results.csv")'